-- Enrichment marathon batch: cname.dev, CoCalc (cocalc.com), Codacy, Code Nation, Code::Blocks, Codeac.io, Codeberg Pages, Codeberg Translate

-- ── cname.dev ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$cname.dev is a free dynamic reverse proxy and domain-mapping service that lets developers point a custom domain or subdomain at any IP address and port without editing DNS records. It exposes a public and private domains API alongside a proxy entry point at map.cname.dev, making it useful for self-hosters, homelab operators, and small projects that need a stable public hostname for a server behind a changing IP.$q$, short_description),
  pricing_model = COALESCE($q$Free service; no publicly disclosed paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed; appears to be a small, independently operated developer tool$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$cname.dev: Free Dynamic Reverse Proxy and Domain Mapping$q$, seo_title),
  seo_meta_description = COALESCE($q$cname.dev lets you map any domain or subdomain to an IP and port without DNS changes. Free reverse proxy and domains API for developers and self-hosters.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$cname.dev is a free, developer-focused dynamic reverse proxy and domain-mapping service. Its core function is to let a user point a domain name or subdomain at an arbitrary IP address and TCP port combination without needing to create or edit a traditional DNS CNAME, A, or SRV record at their own domain registrar or DNS provider. Instead of relying on standard DNS propagation, cname.dev operates its own proxy entry point, documented publicly as map.cname.dev, which receives incoming requests for a mapped hostname and forwards, or reverse-proxies, that traffic to the destination IP and port the user has registered through the service. This is particularly useful for people who run servers on residential or dynamic-IP connections, homelab operators, self-hosters, small indie projects, and hobbyist game-server operators who want a memorable, stable hostname without paying for a static IP or manually updating DNS every time their underlying IP address changes. The service exposes both a public and a private domains API, according to its own status page, which suggests that mapping updates such as adding, removing, or changing a domain's target IP and port can be automated programmatically rather than only through a web dashboard. This API-first design is consistent with how many dynamic-DNS-style and reverse-proxy-as-a-service tools operate: a lightweight client or script on the origin server periodically or on-change notifies the proxy service of the current IP and port, and the proxy layer updates its routing table accordingly, so external traffic continues to reach the origin without interruption. Public information about cname.dev's history, founding team, company structure, and funding is limited. The properties available, the homepage and a Better Stack-powered public status page at status.cname.dev, do not disclose a founding year, headquarters, legal entity, or team size. The status page does show that the service tracks uptime across three components: a public dashboard and homepage referred to as System, a private and public domains API, and the domain-mapping proxy entry point itself, with the API and proxy components experiencing occasional short interruptions, typically minutes, alongside a longer multi-hour incident noted in mid-July 2026. This level of operational transparency, paired with a lack of published corporate details, is typical of a smaller, independently run developer utility rather than a venture-backed company. Because cname.dev sits in the DNS, reverse-proxy, and dynamic-IP-mapping category, it is often discovered alongside dynamic DNS providers, tunneling services, and self-hosted reverse proxy software. It differs from those primarily by removing the need for the end user to touch their own domain's DNS zone at all, instead delegating hostname resolution and traffic forwarding to cname.dev's own infrastructure. Prospective users evaluating it for anything beyond hobby or low-stakes use should independently verify uptime history via the public status page, confirm current terms of service and any usage limits directly on the site, and weigh the lack of public company information against the operational risk of depending on a third-party proxy layer for production traffic. As of the available research, no tiered or paid pricing plans are publicly listed, and the service is presented as free to use.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd1601b35-55c8-4070-a942-c125771f0492';

