-- ── Codacy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codacy is a code quality and security analysis platform that automatically scans source code across 49 languages for style, security, duplication, and complexity issues in pull requests. Founded in 2012 and headquartered in Lisbon, Portugal, it is used by development teams to enforce coding standards, catch vulnerabilities, and track quality metrics over time.$q$, short_description),
  pricing_model = COALESCE($q$Freemium: free plan for individual developers and open-source projects, paid per-developer monthly plans for teams, custom enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free Developer plan; Team plan from $18 per developer per month billed annually$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Roughly 65 to 75 employees, according to third-party company data$q$, company_size),
  headquarters = COALESCE($q$Lisbon, Portugal$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codacy Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Codacy automates code quality and security scanning across 49 languages. See 2026 pricing plans, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codacy is a code quality and security analysis platform founded in 2012 in Lisbon, Portugal, by developers Jaime Jorge and Joao Caxaria. The company is headquartered in Lisbon and has raised roughly 30 million dollars across multiple funding rounds, including a Series B round in 2022, from investors such as Bright Pixel Capital, Armilar Venture Partners, and Faber. Codacy positions itself as a unified code quality and security platform aimed at software development teams that want automated, consistent code review without manually configuring and maintaining separate static analysis tools for every language and repository. The core product integrates with GitHub, GitLab, and Bitbucket to automatically scan every commit and pull request for static analysis violations, security vulnerabilities through static application security testing, software composition analysis for vulnerable dependencies, and hardcoded secrets. Codacy supports scanning for 49 programming languages and aggregates results from a large set of open-source and proprietary linters and security engines behind a single dashboard, so teams do not need to configure tools like ESLint, Pylint, or Bandit individually across every project. The platform reports quality metrics such as code coverage, duplication, complexity, and issue counts over time, and it can enforce merge and quality gates that block pull requests from merging if they introduce new violations or drop coverage below a set threshold. More recently, Codacy has added AI-oriented features aimed at teams that increasingly rely on AI-assisted or AI-generated code, including an IDE plugin for VS Code, JetBrains IDEs, and Cursor that scans code as it is typed and can auto-fix certain issues before code is committed, plus an AI Reviewer that comments on pull requests and an AI Inventory and AI Risk Hub aimed at giving engineering leaders visibility into where and how AI-generated code is entering their codebase. Codacy's pricing follows a three-tier freemium model. The Developer plan is free forever and includes the IDE plugin, security and quality scans, and support for JavaScript and TypeScript, Python, and Java, aimed at individual developers. The Team plan, aimed at teams of up to about 30 developers, starts at 18 dollars per developer per month billed annually, or 21 dollars per developer per month billed monthly, and adds GitHub, Bitbucket, and GitLab integration, up to 100 private repositories with unlimited lines of code, an AI reviewer, merge gates, support for all 49 languages, and integrations with Jira and Slack, while remaining free for qualifying open-source projects. The Business plan is aimed at organizations with 30 or more developers and uses custom pricing, adding unlimited private projects, a priority scan queue, daily re-scans against newly disclosed CVEs, license scanning, dynamic application security testing, container image scanning, custom rules, SSO and SAML, audit logs, and a dedicated customer success manager. Codacy offers a 14-day free trial of paid plans with no credit card required, accepts standard card payments plus wire transfer or ACH for annual plans, and is available through the AWS Marketplace. Codacy is typically compared to tools such as SonarQube and SonarCloud, CodeClimate, DeepSource, and Codeac.io, and it differentiates itself with broad language coverage in a single unified platform, an emphasis on combining code quality and security scanning rather than treating them as separate products, and increasing investment in AI-code-specific guardrails as more development teams adopt AI coding assistants. It is most commonly adopted by engineering teams that want automated pull request checks, security scanning, and quality trend reporting without assembling and maintaining a custom toolchain of individual linters and scanners.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '173b9abf-1695-418b-96a2-735fde0cda14';

