-- ── Code Nation ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Code Nation, originally launched as ScriptEd in 2012, was a United States nonprofit organization that brought free coding courses and work-based learning programs to students in under-resourced high schools, using volunteer professional developers as instructors. The organization ceased operations effective June 3, 2024, after serving thousands of students across multiple US regions over more than a decade.$q$, short_description),
  pricing_model = COALESCE($q$Nonprofit; programs were tuition-free for students and partner schools, funded by corporate and philanthropic donations$q$, pricing_model),
  starting_price = COALESCE($q$Free to students and partner schools; the organization is no longer operating$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Nonprofit organization that ceased operations in 2024; detailed staff counts are not publicly available beyond program statistics$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Code Nation: History, Mission and 2024 Closure$q$, seo_title),
  seo_meta_description = COALESCE($q$Code Nation was a US nonprofit teaching coding to under-resourced high school students. Learn its history, programs, impact and 2024 closure.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Code Nation was a United States-based nonprofit organization dedicated to expanding access to technology careers for students from under-resourced high schools. It was originally founded in 2012 under the name ScriptEd and later rebranded to Code Nation, operating under the motto No Innovation Without Representation. The organization's core premise was that while a large share of people who go on to pursue technology careers first decide to do so during high school, students from low-income backgrounds have dramatically less access to computer science classes, internships, and industry mentors than their peers, and Code Nation aimed to close that gap directly inside partner high schools. Code Nation's model relied on mobilizing hundreds of volunteer professional software and web developers to teach tuition-free coding courses inside partner high schools that otherwise lacked the funding or staff to offer computer science education. Its curriculum began with an introductory web development course and progressed into multi-year Fellowship programs covering more advanced, industry-relevant skills such as source control with Git, working with APIs, and the React JavaScript framework. Beyond classroom instruction, Code Nation's Fellowship program placed students who had completed two or more years in the program into experiential, work-based learning placements at partner technology companies, giving them direct workplace exposure alongside continued advanced coursework. Over more than a decade of operation, Code Nation reported serving 7,485 students across 97 partner schools, working with 145 partner companies across three US regions. According to the organization's own reporting, 67 percent of alumni who completed two or more years in its programs went on to major in or work in a STEM field, and notable alumni have gone on to work at companies including Google, American Express, Oscar Health, and Rent the Runway. The organization was funded through corporate and philanthropic partnerships; for example, the Cognizant U.S. Foundation at one point awarded Code Nation 1 million dollars to support computer science education and job experience for thousands of high school students. Code Nation ceased operations effective June 3, 2024. Its website now hosts a legacy page describing itself as preserving the organization's impact and alumni network, even though the organization is no longer actively running programs or enrolling new students. Because Code Nation is no longer operating, anyone researching it in 2026 should treat it as a historical, closed organization rather than an active service, and should not expect to enroll students, volunteer, or partner with it going forward in the way that was possible before its 2024 closure. Organizations or individuals looking for a similarly structured, currently active nonprofit computer science education program for under-resourced students would need to look at other providers still operating in this space, since Code Nation itself is no longer one of them. For historical or research purposes, information about Code Nation's programs, impact statistics, and closure announcement remains publicly available on its legacy website and in coverage from nonprofit-sector publications that covered organizations working to broaden participation in computer science education.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de6a5e70-4d70-4559-9d98-560bb0650b87';

