-- ── Codeac.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codeac (codeac.io) is an automated code review and code quality CI tool that connects to GitHub, GitLab, and Bitbucket repositories to detect static analysis issues, code duplication, and potential security vulnerabilities in every commit and pull request. Founded in 2019 and based in London, it markets itself as a spell-check for developers aimed at reducing technical debt over time.$q$, short_description),
  pricing_model = COALESCE($q$Freemium: free Open-Source plan, per-user Pro subscription for private repositories, custom Enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free Open-Source plan; Pro plan from $21 per user per month billed annually$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small team; startup-scale, exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Codeac.io Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Codeac.io is an automated code review tool for GitHub, GitLab and Bitbucket. See 2026 pricing, features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codeac, operated at codeac.io, is an automated code quality and code review platform founded in 2019 by Michal Simon and based in London, United Kingdom. The product connects directly to a team's existing GitHub, GitLab, or Bitbucket repositories and automatically analyzes every commit and pull request for new static analysis issues, code duplication, and potential security vulnerabilities through static application security testing, without requiring any local installation or changes to a team's existing CI pipeline. Codeac markets itself informally as a spell-check for developers, framing its role as catching small, avoidable code quality problems automatically and continuously rather than relying purely on manual human code review. Under the hood, Codeac aggregates a range of language-specific static analysis tools and linters, including ESLint and TSLint for JavaScript and TypeScript, alongside first-class support for Python, PHP, Ruby, Go, Java, Kotlin, Solidity, C++, and SCSS. It extends beyond application code into Infrastructure-as-Code scanning, covering Docker, Terraform, Kubernetes manifests, Bash scripts, AWS CloudFormation, and Ansible playbooks, positioning it as a broader DevOps-aware code quality tool rather than a pure application-language linter aggregator. The platform tracks project statistics and quality trends over time, measures cycle time, flags duplicated code blocks, and lets teams fully configure which rules and checks apply to their repositories. A more recent Autofix feature can automatically generate ready-to-review pull requests containing suggested fixes for detected issues, reducing the manual work of resolving flagged problems. Codeac's pricing follows a three-tier structure. The Open-Source plan is free forever and covers unlimited public repositories with a limited private repository allowance, aimed at open-source maintainers. The Pro plan is billed per user, priced at 25 dollars per user per month billed monthly, or 21 dollars per user per month billed annually, roughly a 16 percent discount for annual billing, and unlocks unlimited private repositories with unlimited repository analysis under per-user rather than per-repository pricing, plus priority support and a 14-day free trial with no credit card required. An Enterprise plan offers custom pricing for organizations that need to run analysis behind their own firewall, on-premises, with support for self-hosted GitHub Enterprise and Bitbucket Server instances, aimed at organizations with stricter data residency or security requirements. Payment processing is handled through Stripe. Codeac is typically evaluated alongside similar automated code review and static analysis platforms such as Codacy, CodeClimate, SonarQube and SonarCloud, and DeepSource, and it differentiates itself with straightforward per-user, rather than per-repository or per-line-of-code, pricing, broad Infrastructure-as-Code scanning alongside traditional application code analysis, and a relatively simple no-installation setup that connects directly through a repository host's app marketplace; it is listed on the GitHub Marketplace and the Atlassian Marketplace for Bitbucket. It is most commonly adopted by small to mid-sized engineering teams that want continuous, automated quality and security checks on every pull request without assembling and maintaining a custom stack of individual linters, and by teams managing infrastructure code who want the same automated review applied to Terraform, Kubernetes, and CloudFormation files as to their application code.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fac6626b-f7c1-4156-a37d-fe37a53cbd46';

