-- ── Codeberg Pages ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codeberg Pages is a free static site hosting service run by Codeberg e.V., a nonprofit, community-owned Git hosting platform based in Berlin, Germany. It automatically publishes static websites, such as project homepages, developer blogs, or documentation, from a Git repository to a human-friendly username.codeberg.page address or a custom domain.$q$, short_description),
  pricing_model = COALESCE($q$Free, donation and membership-funded nonprofit service with no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Nonprofit association with over 1,200 members as of November 2025, operated largely by volunteers and a small community team$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Codeberg Pages: Free Static Site Hosting Guide 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Codeberg Pages offers free static website hosting for Git repositories, with custom domains and automatic HTTPS. See setup, features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codeberg Pages is a free static website hosting service provided by Codeberg, a nonprofit, community-run Git hosting platform built on the open-source Forgejo software. Codeberg itself is operated by Codeberg e.V., a registered nonprofit association headquartered in Berlin, Germany, that was established in September 2018 with seven founding members and publicly launched the Codeberg.org platform in January 2019. As of November 2025, Codeberg e.V. reported over 1,200 members, including roughly 786 members with active voting rights, several hundred supporting members, and dozens of corporate supporting members, and it is funded entirely through donations and memberships rather than venture capital, advertising, or data monetization, positioning it explicitly as a free and open-source alternative to commercial platforms like GitHub. Codeberg Pages lets any Codeberg user or organization publish a static website directly from a Git repository, without needing separate hosting infrastructure. The underlying software, called git-pages, is itself free and open-source, developed publicly on Codeberg. Sites are published to a predictable, human-friendly address in the form of username.codeberg.page for a user or organization site, or username.codeberg.page/repository-name for a project-specific site. To set up Pages, a user typically creates a repository, commonly named pages for a user or organization-level site, configures a webhook pointing to the appropriate codeberg.page URL, and sets the webhook's branch filter to a dedicated pages branch; any content pushed to that branch, whether hand-written HTML and CSS or output generated by a static site generator, is automatically deployed. Codeberg Pages supports deployment via Forgejo Actions as an alternative to webhooks, which allows teams to build their site with a static site generator such as Hugo, Jekyll, or Eleventy as part of an automated pipeline before publishing the generated output. Beyond the default codeberg.page subdomain, Codeberg Pages supports custom domains, letting users point their own domain name at their Codeberg-hosted static site, with HTTPS handled automatically, commonly implemented via Let's Encrypt certificates, consistent with Codeberg's broader commitment to free, privacy-respecting infrastructure. Because the service targets static content specifically, it is best suited for project homepages, open-source documentation sites, developer blogs, and simple web experiments, rather than sites requiring server-side application logic or databases. As a nonprofit, donation-funded service, Codeberg Pages has no commercial pricing tiers, no enterprise plan, and no paid support contracts; access is included as part of a standard Codeberg account, which is itself free, though Codeberg does encourage users to become paying members or donors to help sustain the platform's infrastructure costs. Codeberg Pages is most commonly compared to GitHub Pages, GitLab Pages, and similar Git-integrated static hosting services, and it differentiates itself primarily through Codeberg's nonprofit, community-governed structure, European data hosting based in Germany, and its basis in fully open-source infrastructure, namely Forgejo and git-pages, rather than a proprietary commercial platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dbbc30f2-c883-490b-a1c0-4209fcaac555';

