-- ── Codeberg Translate ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Codeberg Translate is Codeberg's hosted Weblate instance, offering a free, web-based continuous localization platform that lets translators contribute to open-source projects hosted on Codeberg without needing to edit translation files or use Git directly. It is operated by Codeberg e.V., the nonprofit behind the Codeberg Git hosting platform, and is available at translate.codeberg.org.$q$, short_description),
  pricing_model = COALESCE($q$Free, donation and membership-funded nonprofit service with no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Operated by Codeberg e.V., a nonprofit association with over 1,200 members as of November 2025, run largely by volunteers$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Codeberg Translate: Free Weblate Localization Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Codeberg Translate is a free Weblate-based localization platform for open-source projects hosted on Codeberg. See how it works, features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Codeberg Translate is a free, web-based continuous localization platform operated by Codeberg e.V., the German nonprofit organization that also runs the Codeberg Git hosting platform. Available at translate.codeberg.org, the service is Codeberg's own hosted instance of Weblate, an established open-source, libre software, web-based translation management system that is used by more than 2,500 free and open-source projects and companies across over 165 countries. Rather than building a proprietary translation tool, Codeberg deliberately chose to deploy and self-host Weblate so that projects hosted on Codeberg could offer a proper localization workflow without depending on a third-party commercial translation product. The core problem Codeberg Translate solves is that, without a dedicated localization platform, translating open-source software requires a translator to have real technical knowledge: they need to know where translation files live in a repository, understand the file format and naming conventions, know how to edit those files correctly, and know how to open a pull request with their changes through Git. Weblate removes that barrier by giving translators a simple web interface that shows only the source-language text, typically English, next to an editable field for the target language, so non-technical bilingual or multilingual contributors can add or correct translations without touching source code, file formats, or Git commands directly. Setting up a project to use Codeberg Translate requires the project maintainer to already be using a standard software translation and internationalization system, such as gettext with .po files or Qt Linguist, since Weblate does not automatically make arbitrary source code translatable on its own; it manages and synchronizes existing translation file formats rather than extracting translatable strings from raw code. To connect a repository to Codeberg Translate, the project maintainer adds the dedicated Codeberg Translate service account as a collaborator on their repository and configures a webhook pointing to the Codeberg Translate hooks endpoint, so that Codeberg notifies the Weblate instance whenever the repository changes; changes made by translators inside Weblate can then be synchronized back to the project's repository, typically via automated pull requests or direct commits depending on configuration. This is used both by Codeberg's own infrastructure and documentation projects and by third-party open-source projects hosted on Codeberg that want a proper localization workflow, and Codeberg has run community events, such as a 2024 Translathon, specifically to encourage broader participation in translating Codeberg-related and community projects. As with the rest of Codeberg's offerings, Codeberg Translate is free to use and funded through Codeberg e.V.'s donation and membership model rather than a commercial subscription; there is no tiered or paid version of the service, and access is generally available to any project already hosted on or connected to Codeberg's Git infrastructure. Codeberg Translate is most naturally compared to Weblate's own hosted commercial offering and to other localization platforms like Crowdin or Transifex, and it differentiates itself by being a free, nonprofit-operated instance specifically tied into the Codeberg open-source hosting ecosystem, run by the same community-governed organization, Codeberg e.V., based in Berlin, Germany, that operates Codeberg's Git hosting and Codeberg Pages static site hosting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ef1474b4-0228-487d-8649-9e8c13af556f';

